+func TestMin(t *testing.T) {
+	t.Parallel()
+	tests := []struct {
+		a, b, want int
+	}{
+		{1, 2, 1},
+		{2, 1, 1},
+		{0, 0, 0},
+		{-1, 1, -1},
+		{100, 50, 50},
+		{-100, -50, -100},
+	}
+
+	for _, tc := range tests {
+		got := min(tc.a, tc.b)
+		if got != tc.want {
+			t.Errorf("min(%d, %d) = %d, want %d", tc.a, tc.b, got, tc.want)
+		}
+	}
+}
