+func TestFindOverlap_EdgeCases(t *testing.T) {
+	t.Parallel()
+	tests := []struct {
+		name string
+		prev []string
+		curr []string
+		want int
+	}{
+		{
+			name: "empty prev",
+			prev: []string{},
+			curr: []string{"a", "b"},
+			want: 0,
+		},
+		{
+			name: "empty curr",
+			prev: []string{"a", "b"},
+			curr: []string{},
+			want: 0,
+		},
+		{
+			name: "no overlap at all",
+			prev: []string{"x", "y", "z"},
+			curr: []string{"a", "b", "c"},
+			want: 0,
+		},
+		{
+			name: "last line of prev in middle of curr",
+			prev: []string{"a", "b", "c"},
+			curr: []string{"x", "c", "d"},
+			want: 2,
+		},
+		{
+			name: "single line prev matches first of curr",
+			prev: []string{"x"},
+			curr: []string{"x", "y", "z"},
+			want: 1,
+		},
+		{
+			name: "complete match",
+			prev: []string{"a", "b"},
+			curr: []string{"a", "b"},
+			want: 2,
+		},
+		{
+			name: "suffix of prev at start of curr",
+			prev: []string{"1", "2", "3", "4", "5"},
+			curr: []string{"4", "5", "6", "7"},
+			want: 2,
+		},
+		{
+			name: "longer than maxCheck lines",
+			prev: make([]string, 100), // 100 lines
+			curr: make([]string, 10),
+			want: 0, // No overlap since slices are empty strings
+		},
+	}
+
+	for _, tc := range tests {
+		t.Run(tc.name, func(t *testing.T) {
+			got := findOverlap(tc.prev, tc.curr)
+			if got != tc.want {
+				t.Errorf("findOverlap() = %d, want %d", got, tc.want)
+			}
+		})
+	}
+}
