+func TestFlush_NilFile(t *testing.T) {
+	a := &Archiver{
+		file: nil, // No file set
+	}
+
+	// flush with nil file should not panic and return nil
+	err := a.flush()
+	if err != nil {
+		t.Errorf("flush() with nil file should return nil, got %v", err)
+	}
+}
