+func TestStartsWithLines_EdgeCases(t *testing.T) {
+	t.Parallel()
+	tests := []struct {
+		name   string
+		lines  []string
+		prefix []string
+		want   bool
+	}{
+		{
+			name:   "empty prefix",
+			lines:  []string{"a", "b"},
+			prefix: []string{},
+			want:   true,
+		},
+		{
+			name:   "empty lines",
+			lines:  []string{},
+			prefix: []string{"a"},
+			want:   false,
+		},
+		{
+			name:   "both empty",
+			lines:  []string{},
+			prefix: []string{},
+			want:   true,
+		},
+		{
+			name:   "single element match",
+			lines:  []string{"x"},
+			prefix: []string{"x"},
+			want:   true,
+		},
+		{
+			name:   "single element no match",
+			lines:  []string{"x"},
+			prefix: []string{"y"},
+			want:   false,
+		},
+	}
+
+	for _, tc := range tests {
+		t.Run(tc.name, func(t *testing.T) {
+			got := startsWithLines(tc.lines, tc.prefix)
+			if got != tc.want {
+				t.Errorf("startsWithLines() = %v, want %v", got, tc.want)
+			}
+		})
+	}
+}
